export interface GeometrySetupInterface {
  mesh?: MeshInterface
  geometry?: BufferGeometry
  watchProps?: string[]
}

export interface GeometryAttributeInterface {
  name: string
  array: ArrayLike<number>
  itemSize: number
  normalized?: boolean
}

// function defaultSetup(): GeometryInterface {
